// NetWorth is the resolver for the netWorth field.
func (r *queryResolver) NetWorth(ctx context.Context) (float64, error) {
	userID := ctx.Value("user_id").(uint)

	// Get all accounts for the user
	var accounts []database.Account
	if err := r.DB.Where("user_id = ?", userID).Find(&accounts).Error; err != nil {
		return 0, fmt.Errorf("failed to fetch accounts")
	}

	var totalNetWorth float64
	for _, account := range accounts {
		// Calculate balance for each account from transactions
		var accountBalance float64
		if err := r.DB.Model(&database.Transaction{}).
			Where("account_id = ?", account.ID).
			Select("COALESCE(SUM(amount), 0)").
			Scan(&accountBalance).Error; err != nil {
			return 0, fmt.Errorf("failed to calculate account balance")
		}
		totalNetWorth += accountBalance
	}

	return totalNetWorth, nil
}

// MonthlySpending is the resolver for the monthlySpending field.
func (r *queryResolver) MonthlySpending(ctx context.Context, year int32, month int32) (float64, error) {
	userID := ctx.Value("user_id").(uint)

	startDate := time.Date(int(year), time.Month(month), 1, 0, 0, 0, 0, time.UTC)
	endDate := startDate.AddDate(0, 1, 0).Add(-time.Second)

	var totalSpending float64
	if err := r.DB.Model(&database.Transaction{}).
		Where("user_id = ? AND amount < 0 AND date BETWEEN ? AND ?", userID, startDate, endDate).
		Select("COALESCE(SUM(ABS(amount)), 0)").Scan(&totalSpending).Error; err != nil {
		return 0, fmt.Errorf("failed to calculate monthly spending")
	}

	return totalSpending, nil
}

// SavingsRate is the resolver for the savingsRate field.
func (r *queryResolver) SavingsRate(ctx context.Context, year int32, month int32) (float64, error) {
	userID := ctx.Value("user_id").(uint)

	startDate := time.Date(int(year), time.Month(month), 1, 0, 0, 0, 0, time.UTC)
	endDate := startDate.AddDate(0, 1, 0).Add(-time.Second)

	var totalIncome, totalSpending float64

	// Get total income (positive transactions)
	if err := r.DB.Model(&database.Transaction{}).
		Where("user_id = ? AND amount > 0 AND date BETWEEN ? AND ?", userID, startDate, endDate).
		Select("COALESCE(SUM(amount), 0)").Scan(&totalIncome).Error; err != nil {
		return 0, fmt.Errorf("failed to calculate income")
	}

	// Get total spending (negative transactions)
	if err := r.DB.Model(&database.Transaction{}).
		Where("user_id = ? AND amount < 0 AND date BETWEEN ? AND ?", userID, startDate, endDate).
		Select("COALESCE(SUM(ABS(amount)), 0)").Scan(&totalSpending).Error; err != nil {
		return 0, fmt.Errorf("failed to calculate spending")
	}

	if totalIncome == 0 {
		return 0, nil
	}

	savingsRate := ((totalIncome - totalSpending) / totalIncome) * 100
	return savingsRate, nil
}

// DebtToIncomeRatio is the resolver for the debtToIncomeRatio field.
func (r *queryResolver) DebtToIncomeRatio(ctx context.Context) (float64, error) {
	userID := ctx.Value("user_id").(uint)

	// Get debt accounts (credit cards, loans)
	var debtAccounts []database.Account
	if err := r.DB.Where("user_id = ? AND type IN ('CREDIT_CARD', 'LOAN')", userID).Find(&debtAccounts).Error; err != nil {
		return 0, fmt.Errorf("failed to fetch debt accounts")
	}

	var totalDebt float64
	for _, account := range debtAccounts {
		// Calculate balance for each debt account from transactions
		var accountBalance float64
		if err := r.DB.Model(&database.Transaction{}).
			Where("account_id = ?", account.ID).
			Select("COALESCE(SUM(amount), 0)").
			Scan(&accountBalance).Error; err != nil {
			return 0, fmt.Errorf("failed to calculate account balance")
		}
		// For debt accounts, negative balances represent debt
		if accountBalance < 0 {
			totalDebt += -accountBalance // Convert to positive debt amount
		}
	}

	// Get monthly income (last 30 days)
	thirtyDaysAgo := time.Now().AddDate(0, 0, -30)
	var monthlyIncome float64
	if err := r.DB.Model(&database.Transaction{}).
		Where("user_id = ? AND amount > 0 AND date >= ?", userID, thirtyDaysAgo).
		Select("COALESCE(SUM(amount), 0)").Scan(&monthlyIncome).Error; err != nil {
		return 0, fmt.Errorf("failed to calculate income")
	}

	if monthlyIncome == 0 {
		return 0, nil
	}

	debtToIncomeRatio := (totalDebt / monthlyIncome) * 100
	return debtToIncomeRatio, nil
}

// Mutation returns MutationResolver implementation.
func (r *Resolver) Mutation() MutationResolver { return &mutationResolver{r} }

// Query returns QueryResolver implementation.
func (r *Resolver) Query() QueryResolver { return &queryResolver{r} }

type mutationResolver struct{ *Resolver }
type queryResolver struct{ *Resolver }
